 'pat2': r"project\s+(?:named\s+)?([^\s]+/[^\s,]+).*?\b(\d[\d,]*)\s+forks\b",
 'pat3': r"\b([^\s]+/[^\s,]+)\b.*?\b(\d[\d,]*)\s+forks\b",
}
